class Solution {
    public int maxScoreSightseeingPair(int[] values) {
        int n = values.length;
        int maxScore = Integer.MIN_VALUE;
        for (int i = 0; i < n - 1; i++) {
            for (int j = i + 1; j < n; j++) {
                int score = (values[i] + values[j]) * (i - j);
                maxScore = Math.max(score, maxScore);
            }
        }
        return maxScore;
    }
}
```

